import{_ as t,o as a,c as n,ai as i}from"./chunks/framework.CKB5fCPB.js";const u=JSON.parse('{"title":"Moderation","description":"","frontmatter":{},"headers":[],"relativePath":"Lore/Moderation.md","filePath":"Lore/Moderation.md"}'),o={name:"Lore/Moderation.md"};function s(r,e,l,h,c,d){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="moderation" tabindex="-1">Moderation <a class="header-anchor" href="#moderation" aria-label="Permalink to “Moderation”">​</a></h1><p>The vision of DCTS is self-hosting and self-hosting only and will never be intended to be a central service like discord that will host instances for users. This is fundamentally important to avoid platform decay, single points of failures and more.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>DCTS is distributed as software. Responsibility lies entirely with the operator of each instance.</p></div><hr><h2 id="who-moderates" tabindex="-1">Who moderates? <a class="header-anchor" href="#who-moderates" aria-label="Permalink to “Who moderates?”">​</a></h2><p>Since its about self hosting, the people running an instance are responsible for what happens in that instance. This means taking care of reports and making sure no laws are being broken. DCTS itself is just the software and will only focus on making the software and will not be responsible for what others do with it.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you&#39;re not sure what an instance is, check out <a href="./Terminology">Terminology</a>.</p></div><hr><h2 id="issues-with-an-instance" tabindex="-1">Issues with an instance? <a class="header-anchor" href="#issues-with-an-instance" aria-label="Permalink to “Issues with an instance?”">​</a></h2><p>If you ever find issues about an instance try to reach out to an instance admin. On a properly setup instance you should find contact information on the server info screen. Check out <a href="./../Web Client/Main/Instance Info">Instance Info</a> for that.</p><p>If you suspect illegal content or similar activities report the instance to the authorities. For that you will likely need the instance url, which is the link you use to connect to it. Its basically like reporting a bad website.</p><hr><h2 id="federation" tabindex="-1">Federation <a class="header-anchor" href="#federation" aria-label="Permalink to “Federation”">​</a></h2><p>Its planned to have specific moderation actions federated in the future, like sharing bans between instances and more. The general idea is that if an user was banned from x amount of instances, that if that user would connect to your instance that it may result in an automatic ban or warning.</p><p>This is currently not implement but is one of the goals. Generally speaking this will be optional and your instance has the highest authority, which means these federated events can be viewed as recommendation and help rather than a strict enforcement.</p>',15)])])}const f=t(o,[["render",s]]);export{u as __pageData,f as default};
